CREATE TABLE `feature_plans` (
  `id` int NOT NULL AUTO_INCREMENT,
  `code` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tagline` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `strength` text COLLATE utf8mb4_unicode_ci,
  `sort_order` int DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT NULL,
  `created_at` datetime DEFAULT (now()),
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ix_feature_plans_code` (`code`),
  KEY `ix_feature_plans_id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `feature_plans` (`id`, `code`, `name`, `tagline`, `strength`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (1, 'essential', 'Essential Automation', 'Core HRMS automation for every domain.', 'A complete hire-to-retire operating base for HR, employees, managers, and finance.', 10, 1, '2026-04-30 23:31:47', '2026-05-01 19:03:36');
INSERT INTO `feature_plans` (`id`, `code`, `name`, `tagline`, `strength`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (2, 'strength', 'Strength', 'Advanced automation for distributed and regulated workforces.', 'All Essential features plus deeper workforce management, compliance, employee service, and operational analytics.', 20, 1, '2026-04-30 23:31:47', '2026-05-01 19:03:36');
INSERT INTO `feature_plans` (`id`, `code`, `name`, `tagline`, `strength`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (3, 'growth', 'Growth', 'Talent, skills, culture, and business performance management.', 'All Strength features plus strategic workforce planning, talent development, compensation, and skills intelligence.', 30, 1, '2026-04-30 23:31:47', '2026-05-01 19:03:36');
INSERT INTO `feature_plans` (`id`, `code`, `name`, `tagline`, `strength`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES (4, 'global-enterprise', 'Global Enterprise', 'Mega-suite readiness for any industry and country.', 'Enterprise governance, localization, domain-specific workforce rules, and platform extensibility.', 40, 1, '2026-05-01 19:03:36', NULL);

CREATE TABLE `feedback_360_requests` (
  `id` int NOT NULL AUTO_INCREMENT,
  `cycle_id` int NOT NULL,
  `employee_id` int NOT NULL,
  `reviewer_id` int NOT NULL,
  `relationship_type` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `due_date` date DEFAULT NULL,
  `submitted_at` datetime DEFAULT NULL,
  `responses_json` json DEFAULT NULL,
  `overall_rating` decimal(3,1) DEFAULT NULL,
  `comments` text COLLATE utf8mb4_unicode_ci,
  `created_at` datetime DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `ix_feedback_360_requests_id` (`id`),
  KEY `ix_feedback_360_requests_reviewer_id` (`reviewer_id`),
  KEY `ix_feedback_360_requests_status` (`status`),
  KEY `ix_feedback_360_requests_employee_id` (`employee_id`),
  KEY `ix_feedback_360_requests_cycle_id` (`cycle_id`),
  CONSTRAINT `feedback_360_requests_ibfk_1` FOREIGN KEY (`cycle_id`) REFERENCES `appraisal_cycles` (`id`) ON DELETE CASCADE,
  CONSTRAINT `feedback_360_requests_ibfk_2` FOREIGN KEY (`employee_id`) REFERENCES `employees` (`id`) ON DELETE CASCADE,
  CONSTRAINT `feedback_360_requests_ibfk_3` FOREIGN KEY (`reviewer_id`) REFERENCES `employees` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


CREATE TABLE `field_audit_events` (
  `id` int NOT NULL AUTO_INCREMENT,
  `module` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `entity_type` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `entity_id` int NOT NULL,
  `employee_id` int DEFAULT NULL,
  `field_name` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `action` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `old_value_masked` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `new_value_masked` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
