CREATE TABLE `leave_balance_ledger` (
  `id` int NOT NULL AUTO_INCREMENT,
  `employee_id` int NOT NULL,
  `leave_type_id` int NOT NULL,
  `leave_balance_id` int DEFAULT NULL,
